 1	import React, { FC, useMemo } from 'react';
 2	import { VirtualMachineModel } from 'src/views/dashboard-extensions/utils';
 3	
 4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 6	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 7	import SecretNameLabel from '@kubevirt-utils/components/SSHSecretModal/components/SecretNameLabel';
 8	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 9	import VMSSHSecretModal from '@kubevirt-utils/components/VMSSHSecretModal/VMSSHSecretModal';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import useKubevirtUserSettings from '@kubevirt-utils/hooks/useKubevirtUserSettings/useKubevirtUserSettings';
12	import { asAccessReview } from '@kubevirt-utils/resources/shared';
13	import { getVMSSHSecretName } from '@kubevirt-utils/resources/vm';
14	import { k8sUpdate, K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
15	import { Stack } from '@patternfly/react-core';
16	
17	import { useDynamicSSHInjection } from '../hooks/useDynamicSSHInjection';
18	
19	import DynamicSSHKeyInjectionDescription from './DynamicSSHKeyInjectionDescription';
20	
21	type SSHTabAuthorizedSSHKeyProps = {
22	  isCustomizeInstanceType?: boolean;
23	  onUpdateVM?: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
24	  vm: V1VirtualMachine;
25	};
26	const SSHTabAuthorizedSSHKey: FC<SSHTabAuthorizedSSHKeyProps> = ({
27	  isCustomizeInstanceType,
28	  onUpdateVM,
29	  vm,
30	}) => {
31	  const { t } = useKubevirtTranslation();
32	  const { createModal } = useModal();
33	  const [authorizedSSHKeys, updateAuthorizedSSHKeys, loaded] = useKubevirtUserSettings('ssh');
34	  const accessReview = asAccessReview(VirtualMachineModel, vm, 'update' as K8sVerb);
35	  const [canUpdateVM] = useAccessReview(accessReview || {});
36	  const secretName = useMemo(() => getVMSSHSecretName(vm), [vm]);
37	  const isDynamicSSHInjectionEnabled = useDynamicSSHInjection(vm);
38	  const isEditable =
39	    ((canUpdateVM && isDynamicSSHInjectionEnabled) || isCustomizeInstanceType) && loaded;
40	
41	  const onSubmit = (updatedVM: V1VirtualMachine) =>
42	    onUpdateVM
43	      ? onUpdateVM(updatedVM)
44	      : k8sUpdate({
45	          data: updatedVM,
46	          model: VirtualMachineModel,
47	          name: updatedVM?.metadata?.name,
48	          ns: updatedVM?.metadata?.namespace,
49	        });
50	
51	  return (
52	    <VirtualMachineDescriptionItem
53	      descriptionData={
54	        <Stack hasGutter>
55	          <SecretNameLabel secretName={secretName} />
56	          <DynamicSSHKeyInjectionDescription
57	            isDynamicSSHInjectionEnabled={isDynamicSSHInjectionEnabled}
58	          />
59	        </Stack>
60	      }
61	      onEditClick={() =>
62	        createModal((modalProps) => (
63	          <VMSSHSecretModal
64	            {...modalProps}
65	            authorizedSSHKeys={authorizedSSHKeys}
66	            updateAuthorizedSSHKeys={updateAuthorizedSSHKeys}
67	            updateVM={onSubmit}
68	            vm={vm}
69	          />
70	        ))
71	      }
72	      data-test-id="public-ssh-key"
73	      descriptionHeader={<SearchItem id="public-ssh-key">{t('Public SSH key')}</SearchItem>}
74	      isEdit={isEditable}
75	      showEditOnTitle
76	    />
77	  );
78	};
79	
80	export default SSHTabAuthorizedSSHKey;

